const now = new Date();
const tw = new Date(now.getTime() + 8 * 3600 * 1000);
const yyyy = tw.getUTCFullYear();
const mm = String(tw.getUTCMonth() + 1).padStart(2, '0');
const dd = String(tw.getUTCDate()).padStart(2, '0');
const isoDate   = `${yyyy}-${mm}-${dd}`;
const dateSlug  = `${yyyy}_${mm}_${dd}`;
const compact   = `${yyyy}${mm}${dd}`;
return [{ json: {
  isoDate,
  dateSlug,
  compact,
  pageUrl: 'https://www.taoyuanairport.com.tw/flightforecast'
}}];

const html = $input.first().json.data || '';
const { isoDate, dateSlug, compact } = $('計算日期').first().json;

// ── 多種正則，全面掃描 HTML 屬性中的 .xls / .xlsx 連結 ─────────
const patternSources = [
  /href=["']([^"'<>]*\.xlsx?(?:\?[^"'<>]*)?)["']/gi,
  /href=["']([^"'<>]*\.xlsx?(?:\?[^"'<>]*)?)["']/gi,
  /url:\s*["']([^"'<>]*\.xlsx?(?:\?[^"'<>]*)?)["']/gi,
  /action=["']([^"'<>]*\.xlsx?(?:\?[^"'<>]*)?)["']/gi,
  /["']([^"'<>]*flightforecast[^"'<>]*\.xlsx?(?:\?[^"'<>]*)?)["']/gi,
  /["']([^"'<>]*forecast[^"'<>]*\.xlsx?(?:\?[^"'<>]*)?)["']/gi,
  /["']([^"'<>]*download[^"'<>]*\.xlsx?(?:\?[^"'<>]*)?)["']/gi,
  /["']([^"'<>]*\/files\/[^"'<>]*\.xlsx?(?:\?[^"'<>]*)?)["']/gi,
  /["']([^"'<>]*\/upload\/[^"'<>]*\.xlsx?(?:\?[^"'<>]*)?)["']/gi,
];

const found = new Set();
for (const pat of patternSources) {
  const re = new RegExp(pat.source, 'gi');
  let m;
  while ((m = re.exec(html)) !== null) {
    const u = m[1].trim();
    if (u) found.add(u);
  }
}
const allLinks = [...found];
console.log(`[n8n] 頁面掃描到 ${allLinks.length} 個 XLS 連結: ${JSON.stringify(allLinks)}`);

// 優先選含今日日期字串的連結
let xlsUrl =
  allLinks.find(u => u.includes(dateSlug))  ||
  allLinks.find(u => u.includes(compact))   ||
  allLinks.find(u => u.includes(isoDate))   ||
  allLinks[0] || null;

// ── Fallback：多種日期格式的猜測路徑（依慣例優先度） ─────────────
if (!xlsUrl) {
  const candidates = [
    `https://www.taoyuanairport.com.tw/upload/flightforecast/${dateSlug}.xls`,
    `https://www.taoyuanairport.com.tw/upload/flightforecast/${compact}.xls`,
    `https://www.taoyuanairport.com.tw/upload/flightforecast/${isoDate}.xls`,
    `https://www.taoyuanairport.com.tw/upload/flightforecast/${dateSlug}.xlsx`,
    `https://www.taoyuanairport.com.tw/flightforecast/${dateSlug}.xls`,
    `https://www.taoyuanairport.com.tw/flightforecast/${compact}.xls`,
  ];
  xlsUrl = candidates[0];
  console.warn(`[n8n] ⚠️ 頁面未找到 XLS 連結，使用猜測 URL: ${xlsUrl}`);
}

// 補全相對路徑
if (xlsUrl.startsWith('//')) {
  xlsUrl = 'https:' + xlsUrl;
} else if (xlsUrl.startsWith('/')) {
  xlsUrl = 'https://www.taoyuanairport.com.tw' + xlsUrl;
} else if (!xlsUrl.startsWith('http')) {
  xlsUrl = 'https://www.taoyuanairport.com.tw/' + xlsUrl;
}

const fileExt = /\.xlsx(\?|$)/i.test(xlsUrl) ? 'xlsx' : 'xls';
const xlsName = xlsUrl.split('/').pop()?.split('?')[0] || `${dateSlug}.xls`;

console.log(`[n8n] 最終下載 URL: ${xlsUrl} (format: ${fileExt})`);
return [{ json: { isoDate, dateSlug, compact, xlsUrl, xlsName, fileExt } }];

const item = $input.first();
const binary = item.binary;

// ① 確認 binary 欄位存在
if (!binary?.data) {
  throw new Error(
    '下載失敗：未收到 Binary 資料。\n' +
    '官網可能阻擋了請求或需要登入 Session。'
  );
}

const mimeType = (binary.data.mimeType || '').toLowerCase();
const fileName = (binary.data.fileName  || '').toLowerCase();
const fileSize = binary.data.fileSize   || 0;
const xlsUrl   = $('提取 XLS 下載連結').first().json.xlsUrl;

// ② 最重要的檢查：嚴格拒絕 HTML / 純文字回應
//    這是 "not in xls format" 的根本原因 — HTML 頁面 > 1 KB 會通過大小檢查
const isHtml = mimeType.includes('text/html') || mimeType.includes('text/plain');
const isJson = mimeType.includes('application/json');
if (isHtml || isJson) {
  throw new Error(
    `[MIME 錯誤] 下載到 "${mimeType}" 而非 Excel 檔案（${fileSize} bytes）。\n` +
    `URL: ${xlsUrl}\n\n` +
    `診斷步驟：\n` +
    `1. 手動用瀏覽器開啟 https://www.taoyuanairport.com.tw/flightforecast\n` +
    `2. 右鍵點「下載 XLS」→ 複製連結位址\n` +
    `3. 將真實 URL 填入 Workflow 的「提取 XLS 下載連結」節點 xlsUrl 變數`
  );
}

// ③ 確認不是空檔案或極小的錯誤回應
if (fileSize < 2000) {
  throw new Error(
    `檔案過小 (${fileSize} bytes)，可能為錯誤回應頁面或 404。\n` +
    `URL: ${xlsUrl}`
  );
}

// ④ 從 MIME type 或副檔名偵測格式
let detectedFormat = $('提取 XLS 下載連結').first().json.fileExt || 'xls';
if (mimeType.includes('openxmlformats') || fileName.endsWith('.xlsx')) {
  detectedFormat = 'xlsx';
} else if (
  mimeType.includes('ms-excel') ||
  mimeType.includes('spreadsheet') ||
  mimeType.includes('octet-stream') && fileName.endsWith('.xls') ||
  fileName.endsWith('.xls')
) {
  detectedFormat = 'xls';
}

console.log(`[n8n] ✅ Binary 驗證通過 | size=${fileSize} | mime=${mimeType} | format=${detectedFormat}`);
return [{ json: { ...item.json, detectedFormat }, binary: item.binary }];

// ─── 欄位名稱請依實際 XLS 標題列調整（先執行一次看 output 再修改） ──
const COL_HOUR   = '時段';
const COL_T1_ARR = '第一航廈入境';
const COL_T1_DEP = '第一航廈出境';
const COL_T2_ARR = '第二航廈入境';
const COL_T2_DEP = '第二航廈出境';
// ─────────────────────────────────────────────────────────────────

const items = $input.all();
const hours = [];

for (const item of items) {
  const row = item.json;
  const hour = parseInt(String(row[COL_HOUR]), 10);
  if (isNaN(hour) || hour < 0 || hour > 23) continue;

  hours.push({
    hour,
    forecastCount:
      (Number(row[COL_T1_ARR]) || 0) +
      (Number(row[COL_T1_DEP]) || 0) +
      (Number(row[COL_T2_ARR]) || 0) +
      (Number(row[COL_T2_DEP]) || 0),
    terminal: 'all',
  });
}

const filled = Array.from({ length: 24 }, (_, h) =>
  hours.find(r => r.hour === h) ?? { hour: h, forecastCount: 0, terminal: 'all' }
);

const { isoDate, xlsName } = $('提取 XLS 下載連結').first().json;
return [{ json: { date: isoDate, sourceFile: xlsName, hours: filled } }];

const d = $input.first().json;
console.log(`[n8n] ✅ 寫入成功 | ${d.data?.date} | 尖峰 ${d.data?.peakHour}:00 | 總人次 ${d.data?.totalForecast}`);
return $input.all();

const d = $input.first().json;
console.error('[n8n] ❌ 寫入失敗:', JSON.stringify(d));
return $input.all();
